+@page "/board"
+@using sv_f2f94c4442374fa3a5268b580ed7bb99.Components.Board
+@inject ITaskService TaskService
+@rendermode InteractiveServer
+
+<PageTitle>Kanban Board</PageTitle>
+
+<h3 class="mb-3">Kanban Board</h3>
+
+@if (isLoading)
+{
+    <div class="d-flex justify-content-center p-5">
+        <div class="spinner-border" role="status">
+            <span class="visually-hidden">Loading...</span>
+        </div>
+    </div>
+}
+else if (errorMessage is not null)
+{
+    <div class="alert alert-danger">
+        <strong>Error:</strong> @errorMessage
+        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
+    </div>
+}
+else
+{
+    <BoardStats TotalCount="filteredTasks.Count"
+                TodoCount="todoTasks.Count"
+                InProgressCount="inProgressTasks.Count"
+                DoneCount="doneTasks.Count"
+                OverdueCount="filteredTasks.Count(t => t.DueDate < DateTime.Today)" />
+
+    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />
+
+    <div class="row g-3">
+        <KanbanColumn ColumnName="To Do"
+                      Tasks="todoTasks"
+                      CanMoveLeft="false"
+                      CanMoveRight="true"
+                      OnMoveTask="HandleMoveTask"
+                      OnTaskCreated="HandleTaskCreated" />
+
+        <KanbanColumn ColumnName="In Progress"
+                      Tasks="inProgressTasks"
+                      CanMoveLeft="true"
+                      CanMoveRight="true"
+                      OnMoveTask="HandleMoveTask"
+                      OnTaskCreated="HandleTaskCreated" />
+
+        <KanbanColumn ColumnName="Done"
+                      Tasks="doneTasks"
+                      CanMoveLeft="true"
+                      CanMoveRight="false"
+                      OnMoveTask="HandleMoveTask"
+                      OnTaskCreated="HandleTaskCreated" />
+    </div>
+}
+
+@code {
+    private List<TaskItem> allTasks = new();
+    private string searchText = string.Empty;
+    private bool isLoading = true;
+    private string? errorMessage;
+
+    private static readonly string[] ColumnOrder = ["To Do", "In Progress", "Done"];
+
+    private List<TaskItem> filteredTasks => string.IsNullOrWhiteSpace(searchText)
+        ? allTasks
+        : allTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
+
+    private List<TaskItem> todoTasks => filteredTasks.Where(t => t.Status == "To Do").ToList();
+    private List<TaskItem> inProgressTasks => filteredTasks.Where(t => t.Status == "In Progress").ToList();
+    private List<TaskItem> doneTasks => filteredTasks.Where(t => t.Status == "Done").ToList();
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadTasks();
+    }
+
+    private async Task LoadTasks()
+    {
+        isLoading = true;
+        errorMessage = null;
+
+        try
+        {
+            allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private void HandleSearchChanged(string text)
+    {
+        searchText = text;
+    }
+
+    private async Task HandleMoveTask((int TaskId, int Direction) move)
+    {
+        var task = allTasks.FirstOrDefault(t => t.Id == move.TaskId);
+        if (task is null) return;
+
+        var currentIndex = Array.IndexOf(ColumnOrder, task.Status);
+        var newIndex = currentIndex + move.Direction;
+
+        if (newIndex < 0 || newIndex >= ColumnOrder.Length) return;
+
+        var newStatus = ColumnOrder[newIndex];
+
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
+            // Update the local list with the new status
+            var index = allTasks.FindIndex(t => t.Id == task.Id);
+            allTasks[index] = task with { Status = newStatus };
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+    }
+
+    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate, string Status) data)
+    {
+        try
+        {
+            var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
+            // The service may return the task with a default status; override with the column's status
+            allTasks.Add(newTask with { Status = data.Status });
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+    }
+}
